// Some portions generated by Codex
package org.eclipse.rdf4j.benchmark.common;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.List;

import org.eclipse.rdf4j.benchmark.rio.util.ThemeDataSetGenerator.Theme;
import org.junit.jupiter.api.Test;

class ThemeQueryCatalogSparseTest {

	@Test
	void sparseThemeHasThirteenSchemaOrgQueries() {
		Theme theme = Enum.valueOf(Theme.class, "SPARSE");
		List<String> queries = ThemeQueryCatalog.queriesFor(theme);

		assertEquals(ThemeQueryCatalog.QUERY_COUNT, queries.size());
		assertTrue(queries.stream().allMatch(query -> query.contains("PREFIX schema: <https://schema.org/>")));
	}

	@Test
	void sparseQueriesCoverDeepOptionalsUnionAndIntegerFilters() {
		Theme theme = Enum.valueOf(Theme.class, "SPARSE");
		List<String> queries = ThemeQueryCatalog.queriesFor(theme);

		assertTrue(queries.stream()
				.anyMatch(query -> containsAll(query,
						"?person schema:memberOf ?org",
						"?org schema:department ?department",
						"?department schema:makesOffer ?offer",
						"?offer schema:itemOffered ?work",
						"?work schema:about ?topic",
						"?topic schema:mainEntityOfPage ?page")));
		assertTrue(queries.stream().filter(query -> query.contains("OPTIONAL")).count() >= 8);
		assertTrue(queries.stream().filter(query -> query.contains("UNION")).count() >= 3);
		assertTrue(queries.stream().filter(query -> query.contains(" IN (")).count() >= 4);
		assertTrue(queries.stream()
				.anyMatch(query -> containsAll(query,
						"OPTIONAL {",
						"?rating schema:ratingValue ?stars",
						"FILTER(?stars IN (4, 5))")));
	}

	private static boolean containsAll(String input, String... fragments) {
		for (String fragment : fragments) {
			if (!input.contains(fragment)) {
				return false;
			}
		}
		return true;
	}
}
